/* Pixel art rendering */
.pixel-icon {
  image-rendering: pixelated;
  image-rendering: crisp-edges;
  flex-shrink: 0;
}

/* Blog post prose styles (replaces @tailwindcss/typography for Tailwind v4) */
.prose-content {
  font-size: 0.9375rem;
  line-height: 1.8;
  color: var(--muted);
}

.prose-content p {
  margin-bottom: 1.375rem;
}

.prose-content h2 {
  font-size: 1.05rem;
  font-weight: 700;
  color: #000;
  margin: 2.25rem 0 0.75rem;
  letter-spacing: -0.01em;
}

.prose-content h3 {
  font-size: 0.95rem;
  font-weight: 600;
  color: #000;
  margin: 1.75rem 0 0.5rem;
}

.prose-content a {
  color: #000;
  text-decoration: underline;
  text-underline-offset: 4px;
}

.prose-content a:hover {
  color: var(--muted);
}

.prose-content ul {
  list-style: disc;
  padding-left: 1.5rem;
  margin-bottom: 1.375rem;
}

.prose-content ol {
  list-style: decimal;
  padding-left: 1.5rem;
  margin-bottom: 1.375rem;
}

.prose-content li {
  margin-bottom: 0.4rem;
}

.prose-content blockquote {
  border-left: 2px solid var(--border);
  padding-left: 1.125rem;
  color: var(--muted);
  margin: 1.75rem 0;
  font-style: italic;
}

.prose-content code {
  font-size: 0.8em;
  background: #f5f5f5;
  padding: 0.15em 0.35em;
  border-radius: 3px;
  font-family: ui-monospace, monospace;
}

.prose-content pre {
  background: #f5f5f5;
  padding: 1rem 1.25rem;
  border-radius: 6px;
  overflow-x: auto;
  margin-bottom: 1.375rem;
}

.prose-content pre code {
  background: none;
  padding: 0;
  font-size: 0.85em;
}

.prose-content strong {
  color: #000;
  font-weight: 600;
}

.prose-content hr {
  border: none;
  border-top: 1px solid var(--border);
  margin: 2rem 0;
}

